import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Login = () => {
  const [formData, setFormData] = useState({
    LoginName: '',
    Password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      if (!response.data) {
        throw new Error('No response data received from server');
      }
      const token = response.data.Token;
      if (!token) {
        throw new Error('No token received from server');
      }
      let userInfo;
      try {
        const tokenData = JSON.parse(atob(token.split('.')[1]));
        userInfo = {
          Username: formData.LoginName,
          ClientCode: tokenData.ClientCode
        };
        if (!userInfo.ClientCode) {
          throw new Error('Client code not found in token');
        }
      } catch (tokenError) {
        throw new Error('Failed to extract client code from token');
      }
      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      toast.success(`Welcome ${userInfo.Username}!`, {
        position: "top-right",
        autoClose: 2000,
        theme: "colored"
      });
      navigate('/dashboard');
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontFamily: 'Poppins, Montserrat, Arial, sans-serif'
    }}>
      <ToastContainer />
      <div style={{
        minWidth: 350,
        maxWidth: 400,
        width: '100%',
        background: 'rgba(255, 255, 255, 0.95)',
        borderRadius: 20,
        boxShadow: '0 8px 32px 0 rgba(31, 38, 135, 0.2)',
        backdropFilter: 'blur(10px)',
        border: '1px solid rgba(255, 255, 255, 0.18)',
        padding: '2.8rem 2.5rem',
        margin: '2rem 0'
      }}>
        <div className="text-center mb-4">
          <div style={{ 
            fontSize: '2.5rem', 
            marginBottom: '0.5rem',
            background: 'linear-gradient(45deg, #FF6B6B, #4ECDC4)',
            WebkitBackgroundClip: 'text',
            WebkitTextFillColor: 'transparent'
          }}>
            <i className="fas fa-rss"></i>
          </div>
          <h3 className="mb-2 fw-bold" style={{ 
            fontSize: '1.6rem', 
            color: '#333',
            textAlign: 'center', 
            letterSpacing: 0.5
          }}>RFID Dashboard</h3>
          <p style={{ color: '#666', fontSize: '0.95rem' }}>Sign in to your account</p>
        </div>
        
        {error && (
          <div className="alert alert-danger py-2" style={{ 
            fontSize: '0.98rem',
            borderRadius: '10px',
            border: 'none',
            background: 'rgba(220, 53, 69, 0.1)',
            color: '#dc3545'
          }}>{error}</div>
        )}
        
        <form onSubmit={handleSubmit} autoComplete="off">
          <div className="mb-3">
            <label htmlFor="LoginName" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#555',
              fontSize: '0.9rem',
              marginBottom: '0.4rem'
            }}>
              <i className="fas fa-envelope me-2 text-primary"></i>Email
            </label>
            <input
              type="text"
              className="form-control"
              id="LoginName"
              name="LoginName"
              value={formData.LoginName}
              onChange={handleChange}
              required
              placeholder="Enter your email"
              style={{ 
                fontSize: '1.05rem', 
                background: 'rgba(255, 255, 255, 0.8)', 
                border: '1px solid #e0e0e0', 
                borderRadius: 12,
                padding: '0.6rem 1rem',
                transition: 'all 0.3s',
                boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
              }}
            />
          </div>
          
          <div className="mb-4 position-relative">
            <label htmlFor="Password" className="form-label" style={{ 
              fontWeight: 600, 
              color: '#555',
              fontSize: '0.9rem',
              marginBottom: '0.4rem'
            }}>
              <i className="fas fa-lock me-2 text-primary"></i>Password
            </label>
            <input
              type={showPassword ? 'text' : 'password'}
              className="form-control"
              id="Password"
              name="Password"
              value={formData.Password}
              onChange={handleChange}
              required
              placeholder="Enter password"
              style={{ 
                fontSize: '1.05rem', 
                background: 'rgba(255, 255, 255, 0.8)', 
                border: '1px solid #e0e0e0', 
                borderRadius: 12,
                padding: '0.6rem 1rem',
                transition: 'all 0.3s',
                boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
              }}
            />
            <span
              onClick={() => setShowPassword(s => !s)}
              style={{
                position: 'absolute',
                right: 14,
                top: 38,
                cursor: 'pointer',
                color: '#6c757d',
                fontSize: '1.1rem'
              }}
              tabIndex={0}
              role="button"
              aria-label="Toggle password visibility"
            >
              <i className={`fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
            </span>
          </div>
          
          <button
            type="submit"
            className="btn w-100 fw-bold"
            style={{
              fontSize: '1.1rem',
              background: 'linear-gradient(45deg, #2193b0, #6dd5ed)',
              color: '#fff',
              border: 'none',
              borderRadius: 12,
              padding: '0.6rem',
              marginTop: 8,
              marginBottom: 12,
              boxShadow: '0 4px 10px rgba(33, 147, 176, 0.3)',
              transition: 'all 0.3s'
            }}
            disabled={loading}
            onMouseOver={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #1c7a94, #5ec2d9)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.background = 'linear-gradient(45deg, #2193b0, #6dd5ed)';
              e.currentTarget.style.transform = 'translateY(0)';
            }}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              <>
                <i className="fas fa-sign-in-alt me-2"></i>
                Sign in
              </>
            )}
          </button>
        </form>
        
        <div className="text-center mt-4" style={{ fontSize: '0.98rem', color: '#555' }}>
          Don&apos;t have an account?{' '}
          <span
            className="fw-bold"
            style={{ 
              color: '#2193b0', 
              cursor: 'pointer',
              textDecoration: 'underline',
              transition: 'all 0.3s'
            }}
            onClick={() => navigate('/register')}
          >
            Sign up now
          </span>
        </div>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Login;
